1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Edge cases: simplest ---
6	  it("empty item list quote → premium 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Single main item base premiums + processing fee ---
15	  it("quote single sword (steel, ench 3, not cursed), 0 yrs, 1st contract → 115 G", () => {
16	    const result = runScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [
19	        {
20	          op: "quote",
21	          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
22	        },
23	      ],
24	    });
25	    expect(result).toEqual({ results: [{ premium: 115 }] });
26	  });
27	  it("quote single amulet → 71 G (60 + 6 first + 5 fee)", () => {
28	    const result = runScenario({
29	      customer: { yearsWithMHPCO: 0 },
30	      steps: [{ op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }] }],
31	    });
32	    expect(result).toEqual({ results: [{ premium: 71 }] });
33	  });
34	  it("quote single staff → 93 G (80 + 8 first + 5 fee)", () => {
35	    const result = runScenario({
36	      customer: { yearsWithMHPCO: 0 },
37	      steps: [{ op: "quote", items: [{ type: "staff", material: "oak", enchantment: 1, cursed: false }] }],
38	    });
39	    expect(result).toEqual({ results: [{ premium: 93 }] });
40	  });
41	  it("quote single potion → 49 G (40 + 4 first + 5 fee)", () => {
42	    const result = runScenario({
43	      customer: { yearsWithMHPCO: 0 },
44	      steps: [{ op: "quote", items: [{ type: "potion" }] }],
45	    });
46	    expect(result).toEqual({ results: [{ premium: 49 }] });
47	  });
48	
49	  // --- Components: rune / moonstone single & multiple, blocks ---
50	  it("quote 1 rune → 33 G (25 + 2.5 first + 5 fee = 32.5 → ceil 33)", () => {
51	    const result = runScenario({
52	      customer: { yearsWithMHPCO: 0 },
53	      steps: [{ op: "quote", items: [{ type: "rune" }] }],
54	    });
55	    expect(result).toEqual({ results: [{ premium: 33 }] });
56	  });
57	  it.todo("quote 2 runes → 50 G base premium (per spec example)");
58	  it.todo("quote 3 runes → 60 G base premium (block of 3 alike applies)");
59	  it.todo("quote 4 runes → 100 G base premium (no block; block requires exactly 3)");
60	  it.todo("quote 7 runes → 175 G base premium (7 × 25, no block)");
61	
62	  // --- Alike-component clarification (❓) ---
63	  it.todo("quote 2 runes + 1 moonstone → 75 G base premium (no block: different types)");
64	  it.todo("quote 3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
65	
66	  // --- Modifier scope on multi-item policies (❓) ---
67	  it.todo("policy with cursed sword + plain amulet → 210 G before further modifiers and fee (curse surcharge on sword only)");
68	
69	  // --- Modifier thresholds ---
70	  it.todo("loyalty: exactly 2 years with MHPCO → loyalty discount applies");
71	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
72	  it.todo("sword with enchantment 5 and cursed → both surcharges apply");
73	  it.todo("sword with enchantment 4 not cursed → no high-enchantment, no curse surcharge");
74	  it.todo("sword with enchantment 4 and cursed → no high-enchantment surcharge; curse applies");
75	
76	  // --- Rounding in MHPCO's favor ---
77	  it.todo("premium calculation yielding 197.5 G → 198 G (rounded up)");
78	  it.todo("payout calculation yielding 350.5 G → 350 G (rounded down)");
79	  it.todo("intermediate amounts kept as fractions; only final rounded");
80	
81	  // --- Claim processing: standard reimbursement ---
82	  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (full − 100 deductible)");
83	  it.todo("rune damage 200 G → payout 100 G (full − 100 deductible; no special clauses for components)");
84	
85	  // --- Claim: enchantment threshold & dragon material interactions ---
86	  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (high-ench wins, 50% then deductible)");
87	  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
88	  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (dragon full reimbursement − deductible)");
89	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (high-ench: 50% − deductible)");
90	
91	  // --- Deductible per damage event ---
92	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (100 deductible per item)");
93	
94	  // --- Multiple items of the same type ---
95	  it.todo("policy of two swords → insurance sum 2000 G, cap 4000 G");
96	  it.todo("policy of two swords, both damaged → each entry has its own deductible");
97	  it.todo("damages array has more entries of a type than policy covers → CLI exits non-zero (claim rejected)");
98	
99	  // --- Cap exhaustion ---
100	  it.todo("policy with sword + amulet → insurance sum 1600 G, cap 3200 G");
101	  it.todo("cursed sword (premium with modifiers 165) → cap 2000 G (based on unmodified insurance value)");
102	  it.todo("policy with sword + 3 runes (block) → insurance sum 1750 G (block discount does not affect insurance sum)");
103	  it.todo("sword cap 2000 G; two successive claims of 1500 each → 1st payout 1400, cap left 600; 2nd payout 600, cap 0");
104	
105	  // --- Integration examples ---
106	  it.todo("newcomer with cursed sword (steel ench 3): 0 yrs, 1st contract → 165 G (100 + 50 curse + 10 first + 5 fee)");
107	  it.todo("long-standing customer 3 yrs, 2nd contract, cursed sword steel ench 7 → 160 G (100+50+30−20+10−15+5)");
108	
109	  // --- Edge cases: error handling ---
110	  it.todo("quote with unknown item type (e.g. broomstick) → CLI exits non-zero, error to stderr");
111	  it.todo("claim references item not in policy (e.g. amulet damaged when only sword insured) → CLI exits non-zero");
112	  it.todo("claim damages includes unknown item type → CLI exits non-zero");
113	  it.todo("claim has damage entry with negative amount → CLI exits non-zero");
114	
115	  // --- CLI/scenario shape ---
116	  it.todo("scenario with quote + claim returns results array of same length and order");
117	  it.todo("claim references policy by zero-based step index");
118	});
119

1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type QuoteStep = { op: "quote"; items: Item[] };
9	export type Step = QuoteStep;
10	
11	export type Scenario = {
12	  customer: { yearsWithMHPCO: number };
13	  steps: Step[];
14	};
15	
16	export type QuoteResult = { premium: number };
17	export type ScenarioResult = { results: QuoteResult[] };
18	
19	const PROCESSING_FEE = 5;
20	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
21	
22	const BASE_PREMIUMS: Record<string, number> = {
23	  sword: 100,
24	  amulet: 60,
25	  staff: 80,
26	  potion: 40,
27	  rune: 25,
28	};
29	
30	const itemPremium = (item: Item): number => {
31	  const basePremium = BASE_PREMIUMS[item.type];
32	  return basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
33	};
34	
35	const quoteStep = (step: QuoteStep): QuoteResult => {
36	  const itemsTotal = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
37	  return { premium: Math.ceil(itemsTotal + PROCESSING_FEE) };
38	};
39	
40	export const runScenario = (scenario: Scenario): ScenarioResult => {
41	  return { results: scenario.steps.map(quoteStep) };
42	};
